#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    std::vector<long long> vals;
    for (int i = 0; i < 62; ++i) {
        for (int j = i + 1; j < 62; ++j) {
            for (int k = j + 1; k < 62; ++k) {
                vals.push_back((1LL << i) + (1LL << j) + (1LL << k));
            }
        }
    }
    std::sort(vals.begin(), vals.end());
    int T;
    std::cin >> T;
    while (T--) {
        long long n;
        std::cin >> n;
        auto it = std::upper_bound(vals.begin(), vals.end(), n);
        if (it == vals.begin()) std::cout << -1 << '\n';
        else std::cout << *std::prev(it) << '\n';
    }
    return 0;
}

