int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (long long& x : a) std::cin >> x;
    std::sort(a.begin(), a.end());
    int pairs = n - m;
    int paired = 2 * pairs;
    long long ans = 0;
    for (int i = 0; i < pairs; ++i) {
        long long s = a[i] + a[paired - 1 - i];
        ans += s * s;
    }
    for (int i = paired; i < n; ++i) ans += a[i] * a[i];
    std::cout << ans << '\n';
    return 0;
}

