    int T;
    std::cin >> T;
    while (T--) {
        long long n, a, b;
        std::cin >> n >> a >> b;
        if (a > n) {
            std::cout << "No\n";
            continue;
        }
        long long rem = n - a;
        long long per_col = std::min(rem, (n + 1) / 2);
        long long cap = rem * per_col;
        std::cout << (b <= cap ? "Yes" : "No") << '\n';
    }
    return 0;
}

#include <algorithm>
#include <iostream>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    long long c;
    std::cin >> n >> c;
    long long total = 0, maxEnd = 0, minEnd = 0, maxSub = 0, minSub = 0;
    for (int i = 0; i < n; ++i) {
        long long x;
        std::cin >> x;
        total += x;
        maxEnd = std::max(0LL, maxEnd + x);
        maxSub = std::max(maxSub, maxEnd);
        minEnd = std::min(0LL, minEnd + x);
        minSub = std::min(minSub, minEnd);
    }
    long long coef = c - 1;
    long long gain = coef >= 0 ? coef * maxSub : coef * minSub;
    std::cout << total + std::max(0LL, gain) << '\n';
    return 0;
}

