int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    std::vector<int> coin = {1, 5, 10, 50, 100, 500};
    std::vector<long long> cnt(6);
    for (long long& x : cnt) std::cin >> x;
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        long long x;
        std::cin >> x;
        for (int j = 5; j >= 0; --j) {
            long long use = std::min(cnt[j], x / coin[j]);
            cnt[j] -= use;
            x -= use * coin[j];
        }
        if (x != 0) {
            std::cout << "No\n";
            return 0;
        }
    }
    std::cout << "Yes\n";
    return 0;
}

