        }
    }
    for (char& ch : diag) if (ch == '?') ch = '0';
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) std::cout << diag[i + j];
        std::cout << '\n';
    }
    return 0;
}

