#include <iostream>
#include <queue>
#include <string>
#include <utility>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int h, w;
    std::cin >> h >> w;
    std::vector<std::string> a(h);
    for (int i = 0; i < h; ++i) std::cin >> a[i];
    std::vector<std::vector<int>> mark(h, std::vector<int>(w, 0));
    for (int i = 0; i < h; ++i) {
        for (int l = 0; l < w;) {
            int r = l;
            while (r < w && a[i][r] == a[i][l]) ++r;
            if (r - l >= 3) for (int j = l; j < r; ++j) mark[i][j] = 1;
            l = r;
        }
    }
    for (int j = 0; j < w; ++j) {
        for (int l = 0; l < h;) {
            int r = l;
            while (r < h && a[r][j] == a[l][j]) ++r;
            if (r - l >= 3) for (int i = l; i < r; ++i) mark[i][j] = 1;
            l = r;
        }
    }
    int ans = 0;
    const int dr[4] = {1, -1, 0, 0};
    const int dc[4] = {0, 0, 1, -1};
    for (int i = 0; i < h; ++i) for (int j = 0; j < w; ++j) {
        if (!mark[i][j]) continue;
        ++ans;
        std::queue<std::pair<int,int>> q;
        q.push({i,j}); mark[i][j] = 0;
        while (!q.empty()) {
            auto [r,c] = q.front(); q.pop();
            for (int d = 0; d < 4; ++d) {
                int nr = r + dr[d], nc = c + dc[d];
                if (0 <= nr && nr < h && 0 <= nc && nc < w && mark[nr][nc]) {
                    mark[nr][nc] = 0;
                    q.push({nr,nc});
                }
            }
        }
    }
    std::cout << ans << '\n';
    return 0;
}

