#include <iostream>
#include <unordered_map>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    long long k;
    std::cin >> n >> k;
    std::unordered_map<long long, long long> freq;
    freq.reserve(static_cast<std::size_t>(n) * 2 + 1);
    long long pref = 0, ans = 0;
    freq[0] = 1;
    for (int i = 0; i < n; ++i) {
        long long x;
        std::cin >> x;
        pref += x;
        auto it = freq.find(pref - k);
        if (it != freq.end()) ans += it->second;
        ++freq[pref];
    }
    std::cout << ans << '\n';
    return 0;
}
